#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long x,y;
    node(long long a=0,long long b=0):x(a),y(b){}
};
double slope(node a,node b)
{
    return (b.y-a.y)*1.0/(b.x-a.x);
}
long long c[500010],s[500010],dp[500010];
int main()
{
    long long n,l;
    scanf("%lld%lld",&n,&l);
    l++;
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&c[i]);
        c[i]++;
        s[i]=s[i-1]+c[i];
    }
    deque<node> q;
    q.push_back((node){0,0});
    for(long long i=1;i<=n;i++)
    {
        while(q.size()>1&&s[i]*2>slope(q[0],q[1]))
        {
            q.pop_front();
        }
        node pre=q.front();
        dp[i]=pre.y+(s[i]-l)*(s[i]-l)-s[i]*2*pre.x;
        node now=(node){s[i],dp[i]+s[i]*s[i]+s[i]*l*2};
        while(q.size()>1&&slope(q[q.size()-2],q.back())>slope(q.back(),now))
        {
            q.pop_back();
        }
        q.push_back(now);
    }
    printf("%lld",dp[n]);
    return 0;
}
